oxed{def remove_duplicates(lst):
   seen = set()
   result = []
   for x in lst:
       if x not in seen:
           seen.add(x)
           result.append(x)
   return result}

oxed{def sieve(n):
   is_prime = [True] * (n + 1)
   is_prime[0] = is_prime[1] = False
   for i in range(2, int(n**0.5) + 1):
       if is_prime[i]:
           for j in range(i*i, n+1, i):
               is_prime[j] = False
   return [i for i in range(2, n+1) if is_prime[i]]}

